const body = $('Webhook (RAG Trigger)').first().json.body || {};
const symbol = body.symbol || 'UNKNOWN';
const timeframe = body.timeframe || 'H1';
const context = {
  symbol,
  timeframe,
  episodes_analyzed: 0,
  win_rate_pct: '0.0',
  total_pnl: '0.00',
  breakdown: 'W: 0 | L: 0 | BE: 0',
  rag_context: `No hay episodios historicos disponibles en n8n para ${symbol}. Usa este caso como baseline conservador y prioriza gestion defensiva.`
};
return [{ json: context }];
